  const auto now = node_->now();
  if (!have_odom) {
    publishStop();
    if ((now - t_odom).seconds() < odom_timeout_s_) {
      return BT::NodeStatus::RUNNING;
    }
    RCLCPP_ERROR_THROTTLE(
        node_->get_logger(), *node_->get_clock(), 2000,
        "DriveTowardGoal: odom not received");
