  turn_timeout_s_ = std::max(0.2, getInput<double>("turn_timeout_s").value_or(2.5));
  arc_speed_ = std::max(0.0, getInput<double>("arc_speed").value_or(0.7));
  arc_seconds_ = std::max(0.1, getInput<double>("arc_seconds").value_or(1.4));

